// frontend/src/components/jobs/JobDetails.js
import React, { useState, useEffect } from 'react';
import { useParams, Link, useNavigate } from 'react-router-dom';
import api from '../../services/api';
import { useAuth } from '../../contexts/AuthContext';
import { useAlert } from '../../contexts/AlertContext';
import './JobDetails.css';

const JobDetails = () => {
    const { id } = useParams();
    const navigate = useNavigate();
    const { user, isAuthenticated } = useAuth();
    const alert = useAlert();

    const [job, setJob] = useState(null);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState('');
    const [applying, setApplying] = useState(false);
    const [acceptingId, setAcceptingId] = useState(null);
    const [applicationData, setApplicationData] = useState({
        proposed_rate: '',
        message: ''
    });
    const [clientPackages, setClientPackages] = useState([]);
    const [showPackageModal, setShowPackageModal] = useState(false);
    const [selectedWorker, setSelectedWorker] = useState(null);

    useEffect(() => {
        loadJobDetails();
        if (user?.user_type === 'client') {
            loadClientPackages();
        }
    }, [id, user]);

    const loadJobDetails = async () => {
        setLoading(true);
        try {
            const response = await api.get(`/jobs/${id}`);
            if (response.data.success) {
                setJob(response.data.data);
            } else {
                setError('Job not found');
            }
        } catch (error) {
            console.error('Error loading job:', error);
            setError('Failed to load job details');
        } finally {
            setLoading(false);
        }
    };

    const loadClientPackages = async () => {
        try {
            const response = await api.get('/client/hire-packages');
            if (response.data.success) {
                setClientPackages(response.data.data);
            }
        } catch (error) {
            console.error('Error loading packages:', error);
        }
    };

    const handleInputChange = (e) => {
        const { name, value } = e.target;
        setApplicationData(prev => ({
            ...prev,
            [name]: value
        }));
    };

    const handleApply = async (e) => {
        e.preventDefault();
        if (!isAuthenticated) {
            alert.warning('Please login to apply for jobs');
            navigate('/login', { state: { from: `/jobs/${id}` } });
            return;
        }

        if (user?.user_type !== 'worker') {
            alert.error('Only workers can apply for jobs');
            return;
        }

        if (!applicationData.proposed_rate) {
            alert.warning('Please enter your proposed rate');
            return;
        }

        setApplying(true);

        try {
            const response = await api.post(`/jobs/${id}/apply`, {
                proposed_rate: parseInt(applicationData.proposed_rate),
                message: applicationData.message
            });

            if (response.data.success) {
                alert.success('✅ Application submitted successfully!');
                setApplicationData({ proposed_rate: '', message: '' });
                loadJobDetails();
            } else {
                alert.error(response.data.message || 'Failed to apply');
            }
        } catch (error) {
            console.error('Apply error:', error);
            if (error.response?.status === 400 && error.response?.data?.message === 'You need an active application pass to apply for jobs') {
                alert.confirm(
                    'You need an application pass to apply for jobs. Would you like to buy one now?',
                    () => navigate('/worker/pass'),
                    () => {},
                    'Application Pass Required',
                    'Buy Pass',
                    'Cancel'
                );
            } else {
                alert.error(error.response?.data?.message || 'Failed to apply. Please try again.');
            }
        } finally {
            setApplying(false);
        }
    };

    const handleViewWorkerProfile = (workerId) => {
        navigate(`/workers/${workerId}`, { 
            state: { 
                fromClient: true,
                jobId: job?.id,
                canHire: true 
            } 
        });
    };

    const handleAcceptApplication = (application) => {
        setSelectedWorker(application);
        setShowPackageModal(true);
    };

    const handleHireWorker = async (packageId) => {
        if (!selectedWorker) return;

        setAcceptingId(selectedWorker.id);
        try {
            const response = await api.post(`/jobs/${job.id}/hire`, {
                worker_id: selectedWorker.worker_id,
                package_id: packageId,
                agreed_rate: selectedWorker.proposed_rate
            });

            if (response.data.success) {
                alert.success('✅ Worker hired successfully!');
                setShowPackageModal(false);
                setSelectedWorker(null);
                loadJobDetails();
            }
        } catch (error) {
            console.error('Hire error:', error);
            if (error.response?.status === 400 && error.response?.data?.message?.includes('package')) {
                alert.confirm(
                    'You need a hire package to accept applications. Would you like to buy one now?',
                    () => navigate('/client/packages'),
                    () => {},
                    'Package Required',
                    'Buy Package',
                    'Cancel'
                );
            } else {
                alert.error(error.response?.data?.message || 'Failed to hire worker');
            }
        } finally {
            setAcceptingId(null);
        }
    };

    const formatDate = (dateString) => {
        if (!dateString) return 'Not specified';
        const date = new Date(dateString);
        return date.toLocaleDateString('en-ZA', {
            day: 'numeric',
            month: 'short',
            year: 'numeric'
        });
    };

    const getUrgencyColor = (urgency) => {
        switch (urgency) {
            case 'urgent': return { bg: '#FEE2E2', color: '#DC2626', text: '🚨 Urgent' };
            case 'high': return { bg: '#FEF3C7', color: '#D97706', text: '⚡ High' };
            case 'medium': return { bg: '#DBEAFE', color: '#2563EB', text: '📋 Medium' };
            default: return { bg: '#E5E7EB', color: '#4B5563', text: '🟢 Low' };
        }
    };

    const getInitials = (name) => {
        if (!name) return 'W';
        return name.split(' ').map(n => n[0]).join('').toUpperCase().substring(0, 2);
    };

    const handleBack = () => {
        navigate(-1);
    };

    if (loading) {
        return (
            <div className="loading-container">
                <div className="loading-spinner">Loading job details...</div>
            </div>
        );
    }

    if (error || !job) {
        return (
            <div className="error-container">
                <h2>❌ Error</h2>
                <p>{error || 'Job not found'}</p>
                <button onClick={handleBack} className="btn-primary">Go Back</button>
            </div>
        );
    }

    const urgency = getUrgencyColor(job.urgency);
    const hasApplied = job.applications?.some(app => app.worker_id === user?.id);
    const isOwner = job.client_id === user?.id;
    const isWorker = user?.user_type === 'worker';

    return (
        <div className="job-details-container">
            <div className="job-details">
                {/* Back Button */}
                <div className="back-navigation">
                    <button onClick={handleBack} className="back-button">
                        ← Back to Jobs
                    </button>
                </div>

                {/* Job Header */}
                <div className="job-header">
                    <h1>{job.title}</h1>

                    <div className="job-meta-grid">
                        <div className="meta-item">
                            <span className="meta-icon">📍</span>
                            <span>{job.township || 'Location not specified'}</span>
                        </div>

                        <div className="meta-item">
                            <span className="meta-icon">📅</span>
                            <span>Posted {formatDate(job.created_at)}</span>
                        </div>

                        <div className="meta-item">
                            <span className="meta-icon">📋</span>
                            <span>Job ID: {job.job_code || 'N/A'}</span>
                        </div>

                        <div className="urgency-badge" style={{ backgroundColor: urgency.bg, color: urgency.color }}>
                            {urgency.text}
                        </div>
                    </div>
                </div>

                {/* Budget Card */}
                <div className="budget-card">
                    <div className="budget-info">
                        <span className="budget-label">Budget Range</span>
                        <span className="budget-amount">
                            R {job.budget_min?.toLocaleString()} - R {job.budget_max?.toLocaleString()}
                        </span>
                    </div>
                    {job.estimated_hours && (
                        <div className="estimated-time">
                            ⏱️ Estimated {job.estimated_hours} hours
                        </div>
                    )}
                </div>

                {/* Description Section */}
                <div className="description-section">
                    <h2>Description</h2>
                    <p>{job.description || 'No description provided'}</p>
                </div>

                {/* Details Grid */}
                <div className="details-grid">
                    {job.category && (
                        <div className="detail-card">
                            <span className="detail-label">Category</span>
                            <span className="detail-value">{job.category}</span>
                        </div>
                    )}

                    {job.subcategory && (
                        <div className="detail-card">
                            <span className="detail-label">Subcategory</span>
                            <span className="detail-value">{job.subcategory}</span>
                        </div>
                    )}

                    {job.preferred_date && (
                        <div className="detail-card">
                            <span className="detail-label">Preferred Date</span>
                            <span className="detail-value">{formatDate(job.preferred_date)}</span>
                        </div>
                    )}

                    {job.preferred_time && (
                        <div className="detail-card">
                            <span className="detail-label">Preferred Time</span>
                            <span className="detail-value">{job.preferred_time}</span>
                        </div>
                    )}
                </div>

                {/* Materials Section */}
                {job.materials_provided && (
                    <div className="materials-section">
                        <h2>Materials Provided</h2>
                        <p className="materials-note">✓ Client will provide materials</p>
                        {job.materials_description && (
                            <p className="materials-description">{job.materials_description}</p>
                        )}
                    </div>
                )}

                {/* Safety Requirements */}
                {job.safety_requirements && (
                    <div className="safety-section">
                        <h2>Safety Requirements</h2>
                        <p>{job.safety_requirements}</p>
                    </div>
                )}

                {/* ========== APPLICATIONS SECTION - VISIBLE TO JOB OWNER ========== */}
                {isOwner && (
                    <div className="applications-section">
                        <div className="applications-header">
                            <h2>📋 Applications ({job.applications?.length || 0})</h2>
                            {job.applications?.length > 0 && (
                                <span className="applications-note">
                                    {job.applications.filter(a => a.status === 'pending').length} pending
                                </span>
                            )}
                        </div>

                        {!job.applications || job.applications.length === 0 ? (
                            <div className="no-applications">
                                <div className="no-apps-icon">📭</div>
                                <h3>No applications yet</h3>
                                <p>When workers apply for this job, they'll appear here</p>
                            </div>
                        ) : (
                            <div className="applications-list">
                                {job.applications.map((app) => (
                                    <div key={app.id} className="application-item">
                                        <div className="application-item-header">
                                            <div className="applicant-info">
                                                <button 
                                                    onClick={() => handleViewWorkerProfile(app.worker_id)}
                                                    className="applicant-avatar"
                                                >
                                                    {getInitials(app.worker_name)}
                                                </button>
                                                <div>
                                                    <button 
                                                        onClick={() => handleViewWorkerProfile(app.worker_id)}
                                                        className="applicant-name-link"
                                                    >
                                                        {app.worker_name}
                                                    </button>
                                                    <div className="applicant-rating">
                                                        {'⭐'.repeat(Math.round(app.worker_rating || 0))}
                                                        <span>({app.worker_rating?.toFixed(1) || '0.0'})</span>
                                                    </div>
                                                </div>
                                            </div>
                                            <div className="application-status-badge">
                                                <span className={`status-dot ${app.status}`}></span>
                                                {app.status}
                                            </div>
                                        </div>

                                        <div className="application-item-body">
                                            <div className="proposed-rate">
                                                <span className="rate-label">Proposed Rate:</span>
                                                <span className="rate-value">R {app.proposed_rate}</span>
                                            </div>

                                            {app.message && (
                                                <div className="applicant-message">
                                                    <strong>Message:</strong>
                                                    <p>{app.message}</p>
                                                </div>
                                            )}

                                            <div className="application-meta">
                                                <span>📅 Applied {formatDate(app.created_at)}</span>
                                                {app.worker_skill && (
                                                    <span className="skill-tag">{app.worker_skill}</span>
                                                )}
                                            </div>
                                        </div>

                                        <div className="application-item-footer">
                                            <button 
                                                onClick={() => handleViewWorkerProfile(app.worker_id)}
                                                className="btn-view-profile"
                                            >
                                                View Limited Profile
                                            </button>
                                            {app.status === 'pending' && (
                                                <button 
                                                    onClick={() => handleAcceptApplication(app)}
                                                    className="btn-accept-application"
                                                    disabled={acceptingId === app.id}
                                                >
                                                    {acceptingId === app.id ? 'Processing...' : 'Hire Worker'}
                                                </button>
                                            )}
                                        </div>
                                    </div>
                                ))}
                            </div>
                        )}
                    </div>
                )}

                {/* Apply Section (for workers) */}
                {isWorker && !isOwner && !hasApplied && (
                    <div className="apply-section">
                        <h2>Apply for this job</h2>

                        <form onSubmit={handleApply} className="apply-form">
                            <div className="form-group">
                                <label>Your proposed rate (R)</label>
                                <input
                                    type="number"
                                    name="proposed_rate"
                                    value={applicationData.proposed_rate}
                                    onChange={handleInputChange}
                                    placeholder={`Between R${job.budget_min} - R${job.budget_max}`}
                                    min={job.budget_min}
                                    max={job.budget_max}
                                    required
                                />
                                <small>Suggested range: R{job.budget_min} - R{job.budget_max}</small>
                            </div>

                            <div className="form-group">
                                <label>Message to client (optional)</label>
                                <textarea
                                    name="message"
                                    value={applicationData.message}
                                    onChange={handleInputChange}
                                    placeholder="Tell the client why you're the best person for this job..."
                                    rows="4"
                                />
                            </div>

                            <button 
                                type="submit" 
                                className="btn-submit"
                                disabled={applying}
                            >
                                {applying ? 'Submitting...' : 'Apply for Job'}
                            </button>
                        </form>
                    </div>
                )}

                {/* Already Applied Message */}
                {isWorker && hasApplied && (
                    <div className="applied-message">
                        <span className="applied-icon">✅</span>
                        <div>
                            <h3>You have already applied for this job</h3>
                            <p>Check your dashboard for application status</p>
                        </div>
                        <Link to="/dashboard" className="btn-view-applications">
                            View Dashboard
                        </Link>
                    </div>
                )}

                {/* Login Prompt */}
                {!isAuthenticated && (
                    <div className="login-prompt">
                        <p>Want to apply for this job?</p>
                        <Link to="/login" className="btn-primary">
                            Sign in to Apply
                        </Link>
                    </div>
                )}
            </div>

            {/* Hire Package Modal */}
            {showPackageModal && selectedWorker && (
                <div className="modal-overlay" onClick={() => setShowPackageModal(false)}>
                    <div className="package-modal" onClick={e => e.stopPropagation()}>
                        <div className="modal-header">
                            <h2>🤝 Hire {selectedWorker.worker_name}</h2>
                            <button className="modal-close" onClick={() => setShowPackageModal(false)}>×</button>
                        </div>

                        <div className="modal-body">
                            <div className="hire-summary">
                                <p><strong>Job:</strong> {job.title}</p>
                                <p><strong>Worker:</strong> {selectedWorker.worker_name}</p>
                                <p><strong>Agreed Rate:</strong> R{selectedWorker.proposed_rate}</p>
                            </div>

                            <h3>Select a Hire Package</h3>
                            <div className="package-options">
                                {clientPackages.map(pkg => (
                                    <div key={pkg.id} className="package-option">
                                        <h4>{pkg.name}</h4>
                                        <p className="package-price">R{pkg.price}</p>
                                        <p className="package-hires">{pkg.hires} hires included</p>
                                        <button 
                                            className="btn-select-package"
                                            onClick={() => handleHireWorker(pkg.id)}
                                            disabled={acceptingId === selectedWorker.id}
                                        >
                                            Select Package
                                        </button>
                                    </div>
                                ))}
                            </div>

                            <p className="package-note">
                                Need a package? <Link to="/client/packages">Buy one here</Link>
                            </p>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

export default JobDetails;
